function createRun(client: Client): RouteHandler {
	return async (ctx) => {
		const burrowId = requireParam(ctx, "id");
		const body = await readJsonBody(ctx);
		const input: RunCreateInput = {
			burrowId,
			agentId: requireString(body, "agentId"),
